/**
 * Dashboard - Merchant dashboard with KPIs and analytics
 * Lazy loads StatusChart for improved initial load performance
 */

'use client'

import { lazy, Suspense } from 'react'
import { KPICards } from '@/src/components/KPICards'
import { ActivityFeed } from '@/src/components/ActivityFeed'

// Lazy load StatusChart to defer chart library loading
const StatusChart = lazy(() => import('@/src/components/StatusChart').then(module => ({ default: module.default })))

function StatusChartLoader() {
  return (
    <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100 mb-8">
      <div className="h-6 bg-gray-200 rounded w-1/3 mb-6 animate-pulse" />
      <div className="flex items-center justify-center">
        <div className="w-48 h-48 rounded-full bg-gray-200 animate-pulse" />
      </div>
    </div>
  )
}

export function Dashboard() {
  return (
    <div className="space-y-8">
      {/* Page Header */}
      <div>
        <h1 className="text-2xl font-bold text-gray-900">Dashboard</h1>
        <p className="text-gray-600 mt-1">
          Overview of your delivery performance
        </p>
      </div>

      {/* KPI Cards Grid - 1 col mobile, 3 col desktop */}
      <KPICards />

      {/* Order Status Distribution Chart - lazy loaded */}
      <Suspense fallback={<StatusChartLoader />}>
        <StatusChart />
      </Suspense>

      {/* Recent Activity Feed */}
      <ActivityFeed />
    </div>
  )
}

export default Dashboard